#!/usr/bin/env node
/**
 * generate-knowledge.mjs
 *
 * Reads the ae-ai-starter verified corpus and writes TypeScript data modules
 * into src/js/lib/knowledge/data/.
 *
 * Usage:
 *   node scripts/generate-knowledge.mjs
 *   node scripts/generate-knowledge.mjs --source ../ae-ai-starter/Scripts/verified
 *
 * The generated files are committed to the repo — no runtime dependency on the corpus.
 */

import { existsSync, mkdirSync, readFileSync, readdirSync, writeFileSync } from "fs";
import { dirname, join, resolve } from "path";
import { fileURLToPath } from "url";

const __dirname = dirname(fileURLToPath(import.meta.url));

const args = process.argv.slice(2);
const sourceArgIdx = args.indexOf("--source");
const sourcePath =
  sourceArgIdx !== -1
    ? resolve(args[sourceArgIdx + 1])
    : resolve(__dirname, "..", "..", "ae-ai-starter", "Scripts", "verified");

if (!existsSync(sourcePath)) {
  console.error(`Error: Source path not found: ${sourcePath}`);
  console.error("Pass --source <path> to specify the verified corpus directory.");
  process.exit(1);
}

const effectsDir = join(sourcePath, "effects");
const examplesDir = join(sourcePath, "examples");
const gotchasFile = join(sourcePath, "gotchas.md");
const propertiesDir = join(sourcePath, "properties");
const outputDir = resolve(__dirname, "..", "src", "js", "lib", "knowledge", "data");

if (!existsSync(effectsDir)) {
  console.error(`Error: Effects directory not found: ${effectsDir}`);
  process.exit(1);
}

if (!existsSync(gotchasFile)) {
  console.error(`Error: gotchas.md not found: ${gotchasFile}`);
  process.exit(1);
}

mkdirSync(outputDir, { recursive: true });

function writeModule(filename, contents) {
  writeFileSync(join(outputDir, filename), contents);
}

function writeStringModule(filename, constName, sourceLabel, value) {
  writeModule(
    filename,
    `// AUTO-GENERATED by scripts/generate-knowledge.mjs — do not edit manually
// Source: ${sourceLabel}

export const ${constName} = ${JSON.stringify(value)};
`
  );
}

function writeObjectModule(filename, sourceLabel, contents) {
  writeModule(
    filename,
    `// AUTO-GENERATED by scripts/generate-knowledge.mjs — do not edit manually
// Source: ${sourceLabel}

${contents}
`
  );
}

function readOptionalJson(filename) {
  const filePath = join(propertiesDir, filename);
  if (!existsSync(filePath)) {
    console.warn(`Warning: Missing optional corpus file ${filePath}; generating empty placeholder.`);
    return null;
  }

  try {
    const raw = readFileSync(filePath, "utf-8");
    if (!raw.trim()) {
      console.warn(`Warning: Optional corpus file ${filePath} is empty; generating empty placeholder.`);
      return null;
    }

    return JSON.parse(raw);
  } catch (error) {
    console.warn(`Warning: Could not parse optional corpus file ${filePath}; generating empty placeholder.`);
    return null;
  }
}

function formatDefaultValue(value) {
  if (value === null || value === undefined) return "null";
  if (typeof value === "string") return JSON.stringify(value);
  if (typeof value === "number" || typeof value === "boolean") return String(value);
  return JSON.stringify(value);
}

function flattenPropertyTree(node, depth = 0, lines = []) {
  const indent = "  ".repeat(depth);

  if (node.type === "group" && Array.isArray(node.children)) {
    lines.push(`${indent}${node.name} | ${node.matchName}`);

    for (const child of node.children) {
      flattenPropertyTree(child, depth + 1, lines);
    }

    return lines;
  }

  const valueType = node.valueType || "UNKNOWN";
  const defaultValue = formatDefaultValue(node.defaultValue);
  lines.push(`${indent}${node.name} | ${node.matchName} | ${valueType} | default: ${defaultValue}`);
  return lines;
}

function formatPropertyReference(title, nodes) {
  const lines = [title];

  for (const node of nodes) {
    if (!node) continue;
    if (lines.length > 1) lines.push("");
    flattenPropertyTree(node, 0, lines);
  }

  return lines.join("\n");
}

function formatLayerPropertySections(sections) {
  const entries = Object.entries(sections).filter(([, value]) => value);
  if (entries.length === 0) return "";

  const lines = ["## Layer Properties"];

  for (const [, value] of entries) {
    lines.push("");
    lines.push(value);
  }

  return lines.join("\n");
}

function failInvalidExample(file, message) {
  console.error(`Error: Invalid example ${file}: ${message}`);
  process.exit(1);
}

function validateExample(file, example) {
  if (!example || typeof example !== "object" || Array.isArray(example)) {
    failInvalidExample(file, "expected a JSON object");
  }

  for (const field of ["id", "description", "script"]) {
    if (typeof example[field] !== "string" || example[field].trim() === "") {
      failInvalidExample(file, `${field} must be a non-empty string`);
    }
  }

  if (!Array.isArray(example.keywords) || example.keywords.length === 0) {
    failInvalidExample(file, "keywords must be a non-empty array");
  }

  for (const keyword of example.keywords) {
    if (typeof keyword !== "string" || keyword.trim() === "") {
      failInvalidExample(file, "keywords must contain only non-empty strings");
    }

    if (keyword !== keyword.toLowerCase()) {
      failInvalidExample(file, `keyword "${keyword}" must be lowercase`);
    }
  }

  if (example.notes !== undefined && typeof example.notes !== "string") {
    failInvalidExample(file, "notes must be a string when present");
  }

  const validated = {
    id: example.id,
    description: example.description,
    keywords: example.keywords,
    script: example.script,
  };

  if (example.notes) {
    validated.notes = example.notes;
  }

  return validated;
}

function readExamples() {
  if (!existsSync(examplesDir)) {
    console.warn(
      `Warning: Missing optional corpus directory ${examplesDir}; generating empty examples catalog.`
    );
    return [];
  }

  const files = readdirSync(examplesDir)
    .filter((file) => file.endsWith(".json") && !file.startsWith("_"))
    .sort();

  const examples = [];
  const seenIds = new Set();

  for (const file of files) {
    const filePath = join(examplesDir, file);

    try {
      const raw = readFileSync(filePath, "utf-8");
      const example = JSON.parse(raw);
      const validated = validateExample(file, example);

      if (seenIds.has(validated.id)) {
        failInvalidExample(file, `duplicate id "${validated.id}"`);
      }

      seenIds.add(validated.id);
      examples.push(validated);
    } catch (error) {
      if (error instanceof SyntaxError) {
        failInvalidExample(file, "could not parse JSON");
      }

      throw error;
    }
  }

  return examples;
}

// -- Generate effect index ---------------------------------------------------

const effectFiles = readdirSync(effectsDir)
  .filter((file) => file.endsWith(".json") && !file.startsWith("_"))
  .sort();

const indexLines = [];
const doNotUseWarnings = [];
const catalog = {};

for (const file of effectFiles) {
  try {
    const raw = readFileSync(join(effectsDir, file), "utf-8");
    const effect = JSON.parse(raw);

    if (!effect.displayName || !effect.matchName) continue;

    indexLines.push(`${effect.displayName} | ${effect.matchName}`);

    if (effect.knownAliases?.doNotUse?.length) {
      for (const alias of effect.knownAliases.doNotUse) {
        doNotUseWarnings.push(
          `  - "${alias}" is WRONG for ${effect.displayName} — use "${effect.matchName}"`
        );
      }
    }

    const keywordSet = new Set([
      effect.displayName.toLowerCase(),
      ...(effect.knownAliases?.work || []).map((alias) => alias.toLowerCase()),
      effect.matchName.toLowerCase(),
    ]);
    const properties = (effect.properties || [])
      .filter((prop) => prop.valueType !== "NO_VALUE" && prop.name !== "")
      .map((prop) => ({
        index: prop.index,
        name: prop.name,
        matchName: prop.matchName,
        valueType: prop.valueType,
        defaultValue: prop.defaultValue ?? null,
      }));

    catalog[effect.matchName] = {
      displayName: effect.displayName,
      matchName: effect.matchName,
      keywords: Array.from(keywordSet),
      doNotUse: effect.knownAliases?.doNotUse || [],
      warnings: effect.warnings || [],
      properties,
    };
  } catch {
    console.warn(`Warning: Could not parse ${file}`);
  }
}

const warningBlock =
  doNotUseWarnings.length > 0
    ? `\n\nKnown Wrong matchNames (DO NOT USE):\n${doNotUseWarnings.join("\n")}`
    : "";

writeStringModule(
  "effect-index.ts",
  "EFFECT_INDEX",
  `ae-ai-starter/Scripts/verified/effects/ (${indexLines.length} effects)`,
  indexLines.join("\n") + warningBlock
);

console.log(`✓ effect-index.ts — ${indexLines.length} effects`);
if (doNotUseWarnings.length > 0) {
  console.log(`  + ${doNotUseWarnings.length} dangerous alias warnings`);
}

// -- Generate gotchas --------------------------------------------------------

const gotchasContent = readFileSync(gotchasFile, "utf-8");

writeStringModule("gotchas.ts", "GOTCHAS", "ae-ai-starter/Scripts/verified/gotchas.md", gotchasContent);

console.log(`✓ gotchas.ts — ${gotchasContent.split("\n").length} lines`);

// -- Generate effects detail catalog -----------------------------------------

const catalogEntries = Object.keys(catalog).length;

writeObjectModule(
  "effects-detail.ts",
  `ae-ai-starter/Scripts/verified/effects/ (${catalogEntries} effects)`,
  `export interface EffectDetail {
  displayName: string;
  matchName: string;
  keywords: string[];
  doNotUse: string[];
  warnings: string[];
  properties: Array<{
    index: number;
    name: string;
    matchName: string;
    valueType: string;
    defaultValue: number | number[] | null;
  }>;
}

export const EFFECTS_DETAIL: Record<string, EffectDetail> = ${JSON.stringify(catalog)};
`
);

console.log(`✓ effects-detail.ts — ${catalogEntries} effects`);

// -- Generate shape properties -----------------------------------------------

const shapeData = readOptionalJson("shape-layer.json");
const shapeProperties = shapeData
  ? formatPropertyReference("## Shape Layer Properties", [shapeData.contents, shapeData.transform])
  : "";

writeStringModule(
  "shape-properties.ts",
  "SHAPE_PROPERTIES",
  "ae-ai-starter/Scripts/verified/properties/shape-layer.json",
  shapeProperties
);

console.log(
  `✓ shape-properties.ts — ${shapeProperties ? shapeProperties.split("\n").length : 0} lines`
);

// -- Generate text properties ------------------------------------------------

const textData = readOptionalJson("text-layer.json");
const textProperties = textData
  ? formatPropertyReference("## Text Layer Properties", [
      textData.textProperties,
      textData.pathOptions,
      textData.moreOptions,
      textData.animator,
      textData.animatorProperties,
      textData.animatorSelectors,
      textData.transform,
    ])
  : "";

writeStringModule(
  "text-properties.ts",
  "TEXT_PROPERTIES",
  "ae-ai-starter/Scripts/verified/properties/text-layer.json",
  textProperties
);

console.log(`✓ text-properties.ts — ${textProperties ? textProperties.split("\n").length : 0} lines`);

// -- Generate mask / camera / light properties -------------------------------

const maskData = readOptionalJson("mask.json");
const cameraData = readOptionalJson("camera.json");
const lightData = readOptionalJson("light.json");

const maskProperties = maskData
  ? formatPropertyReference("### Mask", [maskData.maskParade, maskData.mask])
  : "";
const cameraProperties = cameraData
  ? formatPropertyReference("### Camera", [cameraData.cameraOptions])
  : "";
const lightProperties = lightData ? formatPropertyReference("### Light", [lightData.lightOptions]) : "";

const combinedLayerProperties = formatLayerPropertySections({
  mask: maskProperties,
  camera: cameraProperties,
  light: lightProperties,
});

writeObjectModule(
  "layer-properties.ts",
  "ae-ai-starter/Scripts/verified/properties/{mask,camera,light}.json",
  `export const MASK_PROPERTIES = ${JSON.stringify(maskProperties)};
export const CAMERA_PROPERTIES = ${JSON.stringify(cameraProperties)};
export const LIGHT_PROPERTIES = ${JSON.stringify(lightProperties)};
export const LAYER_PROPERTIES = ${JSON.stringify(combinedLayerProperties)};
`
);

console.log(
  `✓ layer-properties.ts — ${combinedLayerProperties ? combinedLayerProperties.split("\n").length : 0} lines`
);

// -- Generate examples -------------------------------------------------------

const examples = readExamples();

writeObjectModule(
  "examples.ts",
  `ae-ai-starter/Scripts/verified/examples/ (${examples.length} examples)`,
  `export interface ExampleEntry {
  id: string;
  description: string;
  keywords: string[];
  script: string;
  notes?: string;
}

export const EXAMPLES: ExampleEntry[] = ${JSON.stringify(examples, null, 2)};
`
);

console.log(`✓ examples.ts — ${examples.length} examples`);

console.log("\nDone. Files written to src/js/lib/knowledge/data/");
